// ─────────────────────────────────────────────────────────────────
// QDRANT STORE — Cree la collection et upsert les vecteurs
// ─────────────────────────────────────────────────────────────────
const articles = $input.all().map(i => i.json);
const QDRANT = 'http://qdrant:6333';

// Step 1: Ensure collection exists
try {
  await this.helpers.httpRequest({
    method: 'PUT',
    url: QDRANT + '/collections/articles',
    headers: { 'Content-Type': 'application/json' },
    body: {
      vectors: {
        size: 768,
        distance: 'Cosine'
      }
    },
    timeout: 10000
  });
  console.log('Qdrant collection ensured');
} catch(e) {
  // Collection may already exist — that is OK
  console.log('Qdrant collection note: ' + e.message);
}

// Step 2: Prepare and upsert points
function hashCode(str) {
  let hash = 5381;
  for (let i = 0; i < str.length; i++) {
    hash = ((hash << 5) + hash) + str.charCodeAt(i);
    hash = hash & hash;
  }
  return Math.abs(hash) % 2147483647; // Keep within 32-bit int range
}

const points = [];
articles.forEach((article, i) => {
  if (Array.isArray(article.embedding) && article.embedding.length === 768) {
    points.push({
      id: hashCode(article.id || article.doi || String(i)),
      vector: article.embedding,
      payload: {
        title: article.title || '',
        doi: article.doi || '',
        year: article.year || '',
        source: article.source || '',
        question: article.question || ''
      }
    });
  }
});

console.log('Points to upsert: ' + points.length + ' / ' + articles.length);

if (points.length > 0) {
  // Upsert in batches of 100
  const BATCH = 100;
  for (let i = 0; i < points.length; i += BATCH) {
    const batch = points.slice(i, i + BATCH);
    try {
      await this.helpers.httpRequest({
        method: 'PUT',
        url: QDRANT + '/collections/articles/points',
        headers: { 'Content-Type': 'application/json' },
        body: { points: batch },
        timeout: 30000
      });
      console.log('Qdrant upsert batch ' + Math.floor(i/BATCH + 1) + ': ' + batch.length + ' points');
    } catch(e) {
      console.log('Qdrant upsert error: ' + e.message);
    }
  }
}

// Return articles (without embeddings to save memory)
return articles.map(a => {
  const { embedding, ...rest } = a;
  return { json: rest };
});
